src=open('src/App.jsx',encoding='utf-8').read()
pat=re.compile(r'(displayName:"([^"]+)"[^}]*?peakYears:\[([^\]]+)\][^}]*?whip:)([\d.]+)')
fixed=[0]; missed=[0]
def repl(m):
    name=m.group(2); years=m.group(3)
    key=f"{name}|{years}"
    if key in WHIP_MAP:
        fixed[0]+=1
        return m.group(1)+str(WHIP_MAP[key])
    missed[0]+=1
    return m.group(0)
new=pat.sub(repl,src)
open('src/App.jsx','w',encoding='utf-8').write(new)
print(f"WHIP fixed on {fixed[0]} cards (unmatched left as-is: {missed[0]})")

# verify spread
vals=re.findall(r'whip:([\d.]+)', new)
from collections import Counter
print("Distinct WHIP values now:", len(set(vals)))
print("Sample distribution:", Counter(vals).most_common(6))
